import { IMessageComposer } from '@nitrots/nitro-renderer';

export class MoveInventoryItemComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(itemRowId: number, fromSlot: number, toSlot: number)
{
this._data = [ itemRowId, fromSlot, toSlot ];
console.log('Packet MoveInventoryItemComposer sent');
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}